const MessageContent = memo(function MessageContent({ content, isStreaming }: { content: string; isStreaming?: boolean }) {
  if (!content) return null
  // Extract <think>...</think> blocks (Qwen3, DeepSeek-R1 reasoning traces).
  // Handle unclosed block during streaming.
  const thinkParts: string[] = []
  let rest = content
  rest = rest.replace(/<think>([\s\S]*?)<\/think>/g, (_, body) => { thinkParts.push(body); return '' })
  // Unclosed trailing block while streaming
  const openIdx = rest.indexOf('<think>')
  let streamingThink: string | null = null
  if (openIdx !== -1) {
    streamingThink = rest.slice(openIdx + '<think>'.length)
    rest = rest.slice(0, openIdx)
  }
  return (
    <>
      {thinkParts.map((t, i) => <ThinkBlock key={`tp-${i}`} content={t} streaming={false} />)}
      {streamingThink !== null && <ThinkBlock content={streamingThink} streaming={true} />}
      {rest && <MessageMarkdown content={rest} isStreaming={isStreaming} />}
    </>
  )
})

// Reasoning models (DeepSeek-R1, Qwen3 /think) emit LaTeX bracket delimiters \[...\] and \(...\),
// but CommonMark escape rules strip the backslash before remark-math runs. Convert to the
// dollar-delimiter form remark-math actually parses.
function normaliseMathDelimiters(src: string): string {
  return src
    .replace(/\\\[([\s\S]*?)\\\]/g, (_, m) => `\n$$\n${m.trim()}\n$$\n`)
    .replace(/\\\(([\s\S]*?)\\\)/g, (_, m) => `$${m.trim()}$`)
}

const MessageMarkdown = memo(function MessageMarkdown({ content, isStreaming }: { content: string; isStreaming?: boolean }) {
  const prepared = useMemo(() => normaliseMathDelimiters(content), [content])
  return (
    <ReactMarkdown
      remarkPlugins={[remarkGfm, remarkMath]}
      rehypePlugins={[rehypeKatex]}
      components={{
        // Code blocks → ArtifactView
        code({ node, className, children, ...props }: any) {
          const isBlock = !props.inline
          const lang = (className ?? '').replace('language-', '')
          if (isBlock) {
            return <ArtifactView code={String(children).replace(/\n$/, '')} language={lang || 'text'} isStreaming={isStreaming} />
          }
          return (
            <code style={{ background: 'rgba(255,255,255,0.1)', padding: '2px 6px', borderRadius: '4px', color: 'var(--crimson)', fontFamily: 'monospace', fontSize: '0.875em' }}>
              {children}
            </code>
          )
        },
        p({ children }: any) {
          return <p style={{ margin: '0 0 8px', lineHeight: 1.7, whiteSpace: 'pre-wrap', wordBreak: 'break-word' }}>{children}</p>
        },
        h1({ children }: any) {
          return <h1 style={{ fontSize: '16px', fontWeight: 'bold', color: 'var(--crimson)', fontFamily: 'monospace', textTransform: 'uppercase', letterSpacing: '0.1em', margin: '16px 0 8px', borderBottom: '1px solid var(--crimson-20)', paddingBottom: '6px' }}>{children}</h1>
        },
        h2({ children }: any) {
          return <h2 style={{ fontSize: '14px', fontWeight: 'bold', color: '#f4f4f5', fontFamily: 'monospace', textTransform: 'uppercase', letterSpacing: '0.08em', margin: '14px 0 6px' }}>{children}</h2>
        },
        h3({ children }: any) {
          return <h3 style={{ fontSize: '13px', fontWeight: 'bold', color: '#a1a1aa', fontFamily: 'monospace', margin: '12px 0 4px' }}>{children}</h3>
        },
        ul({ children }: any) {
          return <ul style={{ margin: '6px 0 10px', paddingLeft: '20px', display: 'flex', flexDirection: 'column', gap: '4px' }}>{children}</ul>
        },
        ol({ children }: any) {
          return <ol style={{ margin: '6px 0 10px', paddingLeft: '20px', display: 'flex', flexDirection: 'column', gap: '4px' }}>{children}</ol>
        },
        li({ children }: any) {
          return <li style={{ fontSize: '14px', color: '#d4d4d8', lineHeight: 1.6 }}>{children}</li>
        },
        blockquote({ children }: any) {
          return <blockquote style={{ borderLeft: '3px solid var(--crimson)', paddingLeft: '12px', margin: '8px 0', color: '#71717a', fontStyle: 'italic' }}>{children}</blockquote>
        },
        table({ children }: any) {
          return (
            <div style={{ overflowX: 'auto', margin: '10px 0' }}>
              <table style={{ borderCollapse: 'collapse', width: '100%', fontSize: '12px', fontFamily: 'monospace' }}>{children}</table>
            </div>
          )
        },
        th({ children }: any) {
          return <th style={{ padding: '6px 12px', background: 'var(--crimson-08)', border: '1px solid rgba(255,255,255,0.07)', color: 'var(--crimson)', textAlign: 'left', fontWeight: 'bold', textTransform: 'uppercase', letterSpacing: '0.05em' }}>{children}</th>
        },
        td({ children }: any) {
          return <td style={{ padding: '6px 12px', border: '1px solid rgba(255,255,255,0.05)', color: '#d4d4d8' }}>{children}</td>
        },
        hr() {
          return <hr style={{ border: 'none', borderTop: '1px solid rgba(255,255,255,0.07)', margin: '12px 0' }} />
        },
        strong({ children }: any) {
          return <strong style={{ color: '#f4f4f5', fontWeight: 'bold' }}>{children}</strong>
        },
        a({ href, children }: any) {
          return <a href={href} style={{ color: 'var(--crimson)', textDecoration: 'underline', textUnderlineOffset: '3px' }} target="_blank" rel="noreferrer">{children}</a>
        },
      }}
    >
      {prepared}
    </ReactMarkdown>
  )
})

import { useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Trash2, Shield, Clock, Zap, Loader2, CheckCircle2, AlertCircle, Sparkles, RefreshCw, Bot } from 'lucide-react'
import { cn } from '../lib/utils'

export default function CleanerView() {
  const [isCleaning, setIsCleaning] = useState(false)
  const [result, setResult] = useState<{ success: boolean, output?: string, error?: string } | null>(null)

  // Smart Cache Scanner states
  const [isScanning, setIsScanning] = useState(false)
  const [categories, setCategories] = useState<{ name: string; sizeBytes: number; paths: string[] }[]>([])
  const [selectedCategories, setSelectedCategories] = useState<string[]>([])
  const [explanations, setExplanations] = useState<Record<string, string>>({})
  const [explaining, setExplaining] = useState<Record<string, boolean>>({})

  const runCleanup = async (type: 'cache' | 'orphans' | 'logs' | 'all') => {
    setIsCleaning(true)
    setResult(null)
    try {
      const res = await (window as any).electron.systemCleanup(type)
      setResult(res)
    } catch (e: any) {
      setResult({ success: false, error: e.message })
    } finally {
      setIsCleaning(false)
    }
  }

  const scanCache = async () => {
    setIsScanning(true)
    setResult(null)
    try {
      const res = await (window as any).electron.systemCleanupAnalyze()
      if (res.success) {
        setCategories(res.categories)
        setSelectedCategories(res.categories.map((c: any) => c.name))
      } else {
        setResult({ success: false, error: res.error || 'Failed to scan storage.' })
      }
    } catch (e: any) {
      setResult({ success: false, error: e.message })
    } finally {
      setIsScanning(false)
    }
  }

  const executeSelectedCleanup = async () => {
    if (selectedCategories.length === 0) return
    setIsCleaning(true)
    setResult(null)
    try {
      const res = await (window as any).electron.systemCleanupExecute(selectedCategories)
      if (res.success) {
        setResult({ success: true, output: res.logs })
        setCategories([])
        setSelectedCategories([])
      } else {
        setResult({ success: false, error: res.error || 'Failed to execute cleanup.' })
      }
    } catch (e: any) {
      setResult({ success: false, error: e.message })
    } finally {
      setIsCleaning(false)
    }
  }

  const askAIExplanation = async (name: string, paths: string[], sizeBytes: number) => {
    setExplaining(prev => ({ ...prev, [name]: true }))
    try {
      const model = localStorage.getItem('vortex-default-model') || 'qwen3:8b'
      const formattedSize = formatSize(sizeBytes)
      const res = await (window as any).electron.ollamaQuickChat({
        model,
        system: "You are Vortex System Specialist, an expert Linux workstation diagnostic assistant. Explain briefly (in 1-2 sentences) what this system or application cache folder is and whether it is 100% safe to clear it.",
        user: `Explain the cache category "${name}" (Paths: ${paths.join(', ')}), size: ${formattedSize}. Is it safe to clear?`
      })
      if (res.success) {
        setExplanations(prev => ({ ...prev, [name]: res.content }))
      } else {
        setExplanations(prev => ({ ...prev, [name]: `AI Error: ${res.error || 'Failed to generate explanation.'}` }))
      }
    } catch (e: any) {
      setExplanations(prev => ({ ...prev, [name]: `AI Error: ${e.message}` }))
    } finally {
      setExplaining(prev => ({ ...prev, [name]: false }))
    }
  }

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 B'
    const k = 1024
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB']
    const i = Math.floor(Math.log(bytes) / Math.log(k))
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i]
  }

  const toggleSelect = (name: string) => {
    if (selectedCategories.includes(name)) {
      setSelectedCategories(selectedCategories.filter(n => n !== name))
    } else {
      setSelectedCategories([...selectedCategories, name])
    }
  }

  const toggleSelectAll = () => {
    if (selectedCategories.length === categories.length) {
      setSelectedCategories([])
    } else {
      setSelectedCategories(categories.map(c => c.name))
    }
  }

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <CleanupCard 
          icon={Clock}
          title="System Logs"
          description="Vacuum journalctl logs older than 3 days to reclaim space."
          onClick={() => runCleanup('logs')}
          loading={isCleaning}
          color="text-signal"
        />
        <CleanupCard 
          icon={Zap}
          title="Package Cache"
          description="Clear old versions of installed packages using paccache."
          onClick={() => runCleanup('cache')}
          loading={isCleaning}
          color="text-amber-500"
        />
        <CleanupCard 
          icon={Shield}
          title="Orphaned Packages"
          description="Remove packages that were installed as dependencies but no longer needed."
          onClick={() => runCleanup('orphans')}
          loading={isCleaning}
          color="text-crimson"
        />
        <CleanupCard 
          icon={Trash2}
          title="Deep Cleanup"
          description="Perform all cleaning operations at once for maximum efficiency."
          onClick={() => runCleanup('all')}
          loading={isCleaning}
          color="text-white"
          featured
        />
      </div>

      {/* Smart Cache Scanner Section */}
      <div className="p-6 rounded-3xl border border-white/5 bg-white/5 flex flex-col space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h2 className="text-xl font-bold uppercase tracking-wide flex items-center space-x-2">
              <Sparkles className="w-5 h-5 text-amber-500" />
              <span>Smart Cache Scanner</span>
            </h2>
            <p className="text-zinc-500 text-xs">
              Scan system logs, pacman cache, and top user cache directories. Ask AI for safe clear analysis.
            </p>
          </div>
          <button
            onClick={scanCache}
            disabled={isScanning || isCleaning}
            className="flex items-center space-x-2 px-4 py-2 rounded-xl bg-white/10 hover:bg-white/20 transition-all font-bold text-xs uppercase tracking-wider disabled:opacity-50 animate-none"
          >
            {isScanning ? (
              <Loader2 className="w-4 h-4 animate-spin" />
            ) : (
              <RefreshCw className="w-4 h-4" />
            )}
            <span>{isScanning ? 'Scanning...' : 'Scan Cache'}</span>
          </button>
        </div>

        {categories.length > 0 && (
          <div className="flex flex-col space-y-4">
            <div className="flex items-center justify-between border-b border-white/5 pb-2">
              <label className="flex items-center space-x-2 cursor-pointer text-xs font-bold text-zinc-400">
                <input
                  type="checkbox"
                  checked={selectedCategories.length === categories.length}
                  onChange={toggleSelectAll}
                  className="rounded border-zinc-700 bg-zinc-800 text-crimson focus:ring-crimson focus:ring-offset-zinc-900"
                />
                <span>Select All ({categories.length} folders found)</span>
              </label>
              <span className="text-xs font-bold text-zinc-400">
                Total reclaimable: {formatSize(categories.filter(c => selectedCategories.includes(c.name)).reduce((sum, c) => sum + c.sizeBytes, 0))}
              </span>
            </div>

            <div className="space-y-3 max-h-96 overflow-y-auto pr-2">
              {categories.map((cat) => (
                <div key={cat.name} className="p-4 rounded-2xl bg-black/20 border border-white/5 flex flex-col space-y-2">
                  <div className="flex items-start justify-between">
                    <div className="flex items-start space-x-3">
                      <input
                        type="checkbox"
                        checked={selectedCategories.includes(cat.name)}
                        onChange={() => toggleSelect(cat.name)}
                        className="mt-1 rounded border-zinc-700 bg-zinc-800 text-crimson focus:ring-crimson focus:ring-offset-zinc-900"
                      />
                      <div>
                        <div className="font-bold text-sm uppercase tracking-wide">{cat.name}</div>
                        <div className="text-[10px] text-zinc-500 font-mono break-all">{cat.paths.join(', ')}</div>
                      </div>
                    </div>
                    <div className="flex items-center space-x-3">
                      <span className="font-mono text-xs font-bold text-zinc-300">{formatSize(cat.sizeBytes)}</span>
                      <button
                        onClick={() => askAIExplanation(cat.name, cat.paths, cat.sizeBytes)}
                        disabled={explaining[cat.name]}
                        title="Ask AI what this cache is and if it's safe to clear"
                        className="p-2 rounded-lg bg-black/40 hover:bg-black/60 border border-white/5 hover:border-white/10 transition-all text-amber-500 hover:text-amber-400 disabled:opacity-50 flex items-center justify-center"
                      >
                        {explaining[cat.name] ? (
                          <Loader2 className="w-3.5 h-3.5 animate-spin" />
                        ) : (
                          <Bot className="w-3.5 h-3.5" />
                        )}
                      </button>
                    </div>
                  </div>

                  {explanations[cat.name] && (
                    <div className="mt-2 p-3 rounded-xl bg-amber-500/5 border border-amber-500/10 text-xs text-amber-200/85 leading-relaxed flex items-start space-x-2">
                      <Sparkles className="w-4 h-4 text-amber-500 flex-shrink-0 mt-0.5" />
                      <span>{explanations[cat.name]}</span>
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="flex justify-end pt-2">
              <button
                onClick={executeSelectedCleanup}
                disabled={selectedCategories.length === 0 || isCleaning}
                className="flex items-center space-x-2 px-6 py-3 rounded-xl bg-crimson hover:bg-crimson-hover transition-all font-bold text-xs uppercase tracking-wider disabled:opacity-50"
              >
                {isCleaning ? (
                  <Loader2 className="w-4 h-4 animate-spin" />
                ) : (
                  <Trash2 className="w-4 h-4" />
                )}
                <span>Clear Selected Cache</span>
              </button>
            </div>
          </div>
        )}
      </div>

      <AnimatePresence>
        {result && (
          <motion.div 
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0 }}
            className={cn(
              "p-6 rounded-3xl border flex flex-col space-y-4",
              result.success ? "bg-emerald-500/10 border-emerald-500/20" : "bg-crimson/10 border-crimson/20"
            )}
          >
            <div className="flex items-center space-x-3">
              {result.success ? (
                <CheckCircle2 className="w-5 h-5 text-emerald-500" />
              ) : (
                <AlertCircle className="w-5 h-5 text-crimson" />
              )}
              <h3 className={cn("font-bold uppercase tracking-wider", result.success ? "text-emerald-500" : "text-crimson")}>
                {result.success ? "Cleanup Protocol Successful" : "Cleanup Protocol Failed"}
              </h3>
            </div>
            <pre className="text-[10px] font-mono text-zinc-400 bg-black/40 p-4 rounded-xl overflow-x-auto whitespace-pre-wrap max-h-64 overflow-y-auto">
              {result.output || result.error}
            </pre>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  )
}

function CleanupCard({ icon: Icon, title, description, onClick, loading, color, featured }: any) {
